#!/usr/bin/env node
/**
 * Score algorithms against in-silico simulation vectors
 *
 * Runs the same multi-algorithm prediction strategies against SIM-* vectors
 * (generated by in-silico-bridge.js) using the simulation's actual
 * future glucose values as ground truth.
 *
 * Usage:
 *   node score-in-silico.js                    # summary table (all engines)
 *   node score-in-silico.js --engine uva-padova # filter to UVA/Padova vectors only
 *   node score-in-silico.js --json             # full JSON
 *
 * Trace: ALG-VERIFY-008, REQ-060
 */

const fs = require('fs');
const path = require('path');

const REPO_ROOT = path.resolve(__dirname, '../..');
const VECTORS_DIR = path.join(REPO_ROOT, 'conformance/in-silico/vectors');

// Load oref0
let determineBasal, tempBasalFunctions;
try {
  determineBasal = require(path.join(REPO_ROOT, 'externals/oref0/lib/determine-basal/determine-basal'));
  tempBasalFunctions = require(path.join(REPO_ROOT, 'externals/oref0/lib/basal-set-temp'));
} catch (e) { /* oref0 not available */ }

// IOB array generator (shared with in-silico-bridge.js)
function generateIobArray(iobSnapshot, dia) {
  const diaMins = (dia || 6) * 60;
  const ticks = 48;
  const iobArray = [];
  const iob0 = iobSnapshot.iob || 0;
  const activity0 = iobSnapshot.activity || 0;
  const basaliob0 = iobSnapshot.basaliob || 0;
  let tau = diaMins / 1.85;
  if (Math.abs(iob0) > 0.01 && Math.abs(activity0) > 0.0001) {
    const r = Math.abs(activity0 / iob0);
    if (r > 0.0001 && r < 0.1) tau = Math.min(diaMins, Math.max(30, 1 / r));
  }
  const basalFrac = (iob0 !== 0) ? (basaliob0 / iob0) : 0.5;
  for (let i = 0; i < ticks; i++) {
    const t = i * 5;
    const decay = Math.exp(-t / tau);
    const tick = {
      iob: iob0 * decay, basaliob: iob0 * decay * basalFrac,
      bolussnooze: 0, activity: activity0 * Math.max(0, decay),
      lastBolusTime: Date.now() - 3600000,
      iobWithZeroTemp: {
        iob: iob0 * decay * 0.8, basaliob: iob0 * decay * basalFrac * 0.8,
        bolussnooze: 0, activity: activity0 * Math.max(0, decay) * 0.8,
        lastBolusTime: 0, time: new Date(Date.now() + t * 60000).toISOString()
      }
    };
    if (i === 0) tick.lastTemp = { date: Date.now() - 300000, duration: 0 };
    iobArray.push(tick);
  }
  return iobArray;
}

// ─── Prediction Algorithms ───

function predictPersistence(vector, steps) {
  const bg = vector.input.glucoseStatus.glucose;
  return Array(steps).fill(Math.round(bg));
}

function predictMomentum(vector, steps) {
  const bg = vector.input.glucoseStatus.glucose;
  const delta = vector.input.glucoseStatus.delta || 0;
  return Array.from({ length: steps }, (_, i) => {
    const damp = Math.exp(-i * 0.03);
    return Math.round(bg + delta * (i + 1) * damp);
  });
}

function predictIobMomentum(vector, steps) {
  const bg = vector.input.glucoseStatus.glucose;
  const delta = vector.input.glucoseStatus.delta || 0;
  const shortDelta = vector.input.glucoseStatus.shortAvgDelta || delta;
  const longDelta = vector.input.glucoseStatus.longAvgDelta || delta;
  const iob = vector.input.iob.iob || 0;
  const sens = vector.input.profile.sensitivity || 40;
  const dia = vector.input.profile.dia || 6;
  const tau = dia * 60 / 1.85;
  const weightedDelta = 0.5 * shortDelta + 0.3 * delta + 0.2 * longDelta;

  return Array.from({ length: steps }, (_, i) => {
    const t = (i + 1) * 5;
    const damp = Math.exp(-i * 0.04);
    const momentum = weightedDelta * (i + 1) * damp;
    const iobDecay = Math.exp(-t / tau);
    const bgFromInsulin = -(iob - iob * iobDecay) * sens;
    return Math.round(Math.max(39, bg + momentum + bgFromInsulin));
  });
}

function predictOref0(vector, steps) {
  if (!determineBasal) return null;
  const inp = vector.input;
  const glucoseStatus = {
    glucose: inp.glucoseStatus.glucose,
    delta: inp.glucoseStatus.delta || 0.1,
    short_avgdelta: inp.glucoseStatus.shortAvgDelta || inp.glucoseStatus.delta || 0.1,
    long_avgdelta: inp.glucoseStatus.longAvgDelta || inp.glucoseStatus.delta || 0.1,
    date: Date.now()
  };
  const iobData = generateIobArray({
    iob: inp.iob.iob, basaliob: inp.iob.basalIob || 0,
    activity: inp.iob.activity || 0
  }, inp.profile.dia || 6);
  const p = inp.profile;
  const profile = {
    current_basal: p.basalRate || 1.0, sens: p.sensitivity || 40, carb_ratio: p.carbRatio || 10,
    target_bg: ((p.targetLow || 100) + (p.targetHigh || 110)) / 2,
    min_bg: p.targetLow || 100, max_bg: p.targetHigh || 110,
    max_basal: p.maxBasal || 4, max_iob: p.maxIob || 5,
    max_daily_safety_multiplier: 3, current_basal_safety_multiplier: 4,
    dia: p.dia || 6, skip_neutral_temps: false,
    enableSMB_with_bolus: false, enableSMB_always: false, enableSMB_with_COB: false,
    enableSMB_with_temptarget: false, enableSMB_after_carbs: false, enableUAM: false,
    maxSMBBasalMinutes: 30, maxUAMSMBBasalMinutes: 30, SMBInterval: 3,
    bolus_increment: 0.05, out_units: 'mg/dL', type: 'current'
  };
  const currentTemp = inp.currentTemp || { rate: 0, duration: 0 };
  const md = inp.mealData || {};
  const mealData = {
    carbs: md.carbs || 0, mealCOB: md.cob || 0,
    slopeFromMaxDeviation: 0, slopeFromMinDeviation: 0,
    lastCarbTime: Date.now() - 7200000
  };

  const origErr = console.error;
  console.error = () => {};
  let result;
  try {
    result = determineBasal(glucoseStatus, currentTemp, iobData, profile,
      { ratio: 1.0 }, mealData, tempBasalFunctions, false, null, Date.now());
  } catch (e) { console.error = origErr; return null; }
  console.error = origErr;

  const pred = result?.predBGs?.IOB;
  return pred && pred.length > 0 ? pred.slice(0, steps) : null;
}

function predictCaptured(vector, steps) {
  const gt = vector.originalOutput?.predBGs?.IOB;
  return gt && gt.length > 0 ? gt.slice(0, steps) : null;
}

// ─── Algorithm Registry ───
const ALGORITHMS = {
  'persistence':  { name: 'Persistence',       fn: predictPersistence },
  'momentum':     { name: 'Momentum',          fn: predictMomentum },
  'iob-momentum': { name: 'IOB-Momentum',      fn: predictIobMomentum },
  'oref0':        { name: 'oref0 (synth IOB)',  fn: predictOref0 },
  'captured':     { name: 'Captured (oracle)',   fn: predictCaptured },
};

// ─── Metrics ───
function computeMetrics(predicted, groundTruth) {
  const minLen = Math.min(predicted.length, groundTruth.length);
  if (minLen === 0) return null;
  let sumAbs = 0, sumSq = 0, dirMatch = 0;
  for (let i = 0; i < minLen; i++) {
    const d = predicted[i] - groundTruth[i];
    sumAbs += Math.abs(d);
    sumSq += d * d;
  }
  for (let i = 1; i < minLen; i++) {
    if (Math.sign(groundTruth[i] - groundTruth[i-1]) === Math.sign(predicted[i] - predicted[i-1])) dirMatch++;
  }
  return {
    mae: Math.round(sumAbs / minLen * 10) / 10,
    rmse: Math.round(Math.sqrt(sumSq / minLen) * 10) / 10,
    dir: minLen > 1 ? Math.round(dirMatch / (minLen - 1) * 1000) / 1000 : 0,
    n: minLen
  };
}

// ─── Main ───
if (!fs.existsSync(VECTORS_DIR)) {
  console.error(`No in-silico vectors found. Run: node in-silico-bridge.js --scenario all --mode both --vectors`);
  process.exit(1);
}

const files = fs.readdirSync(VECTORS_DIR).filter(f => f.endsWith('.json')).sort();
const jsonFlag = process.argv.includes('--json');
const engineIdx = process.argv.indexOf('--engine');
const engineFilter = engineIdx !== -1 ? process.argv[engineIdx + 1] : null;

const algoStats = {};
for (const k of Object.keys(ALGORITHMS)) algoStats[k] = { totalMae: 0, totalDir: 0, n: 0, good: 0, fair: 0, poor: 0 };
const engineCounts = {};

for (const file of files) {
  const vector = JSON.parse(fs.readFileSync(path.join(VECTORS_DIR, file), 'utf8'));
  const vectorEngine = vector.metadata?.engine || 'cgmsim';
  engineCounts[vectorEngine] = (engineCounts[vectorEngine] || 0) + 1;
  if (engineFilter && vectorEngine !== engineFilter) continue;
  const gt = vector.originalOutput?.predBGs?.IOB;
  if (!gt || gt.length < 3) continue;

  for (const [key, algo] of Object.entries(ALGORITHMS)) {
    const pred = algo.fn(vector, gt.length);
    if (!pred) { continue; }
    const m = computeMetrics(pred, gt);
    if (!m) continue;
    algoStats[key].totalMae += m.mae;
    algoStats[key].totalDir += m.dir;
    algoStats[key].n++;
    if (m.mae <= 5) algoStats[key].good++;
    else if (m.mae <= 15) algoStats[key].fair++;
    else algoStats[key].poor++;
  }
}

// Summary
const summary = {};
for (const [k, s] of Object.entries(algoStats)) {
  summary[k] = {
    name: ALGORITHMS[k].name,
    n: s.n,
    avgMae: s.n > 0 ? Math.round(s.totalMae / s.n * 10) / 10 : null,
    avgDir: s.n > 0 ? Math.round(s.totalDir / s.n * 1000) / 1000 : null,
    good: s.good, fair: s.fair, poor: s.poor
  };
}

if (jsonFlag) {
  console.log(JSON.stringify({ engines: engineCounts, filter: engineFilter, results: summary }, null, 2));
} else {
  const engineLabel = engineFilter ? `engine: ${engineFilter}` : `all engines: ${Object.entries(engineCounts).map(([e,c]) => `${e}(${c})`).join(', ')}`;
  console.log('\n╔══════════════════════════════════════════════════════════════════╗');
  console.log(`║      In-Silico Scoring (${engineLabel})`.padEnd(67) + '║');
  console.log('╠══════════════════════════════════════════════════════════════════╣');
  console.log('║ Algorithm           │ MAE   │ Dir%  │ Good │ Fair │ Poor │ N    ║');
  console.log('╟─────────────────────┼───────┼───────┼──────┼──────┼──────┼──────╢');

  const ranked = Object.entries(summary).sort((a, b) => (a[1].avgMae || 999) - (b[1].avgMae || 999));
  for (const [k, s] of ranked) {
    const name = s.name.padEnd(19).slice(0, 19);
    const mae = s.avgMae != null ? s.avgMae.toFixed(1).padStart(5) : '  N/A';
    const dir = s.avgDir != null ? (s.avgDir * 100).toFixed(1).padStart(5) : '  N/A';
    const good = String(s.good).padStart(4);
    const fair = String(s.fair).padStart(4);
    const poor = String(s.poor).padStart(4);
    const n = String(s.n).padStart(4);
    console.log(`║ ${name} │ ${mae} │ ${dir} │ ${good} │ ${fair} │ ${poor} │ ${n} ║`);
  }
  console.log('╚══════════════════════════════════════════════════════════════════╝');
  console.log(`Good: MAE≤5, Fair: MAE≤15, Poor: MAE>15 (tighter thresholds for synthetic data)`);
}
